const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;
const RUNE_BLOCK_PREMIUM = 60;

const ITEM_BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

function sumItemBasePremiums(items: Item[]): number {
  return items.reduce(
    (sum, item) => sum + ITEM_BASE_PREMIUMS[item.type],
    0
  );
}

function isBlockOfThreeRunes(items: Item[]): boolean {
  return items.length === 3 && items.every((item) => item.type === "rune");
}

function calculatePolicyBase(items: Item[]): number {
  if (isBlockOfThreeRunes(items)) {
    return RUNE_BLOCK_PREMIUM;
  }
  return sumItemBasePremiums(items);
}

